    absLibComp: T_Mechatronic_ModularSystem.Mechatronic.Functiongroups.Move

    instantiationTarget: <<Feeder>>

    classToInstantiate: <<Move>>

    instance: <<Move2>>

    ### End of script 'instantiate1' ###

