    UserMessageCollector.addInfo(PROJECT, self, null, "Scripting", info);



    info = "listAfter: " + listAfter;

    UserMessageCollector.addInfo(PROJECT, self, null, "Scripting", info);



    info = "### End of script '" + scriptName + "' ###";

    UserMessageCollector.addInfo(PROJECT, self, null, "Scripting", info);

